  aiOutput.prayer + '</p></div></div><div style="background-color: #34495e; color: #ecf0f1; 
  padding: 30px; text-align: center;"><p style="margin: 0; font-size: 14px;">Ora et Labora<br><a
   href="' + readingsData.usccbLink + '" style="color: #3498db; text-decoration: none;">View 
  Today\'s Official Readings</a></p></div></div></body></html>';

  return {
    htmlContent: htmlContent,
    subject: 'Daily Benedictine Reflection - ' + dateInfo.today,
    aiOutput: aiOutput,
    dateInfo: dateInfo
  };

// Parse AI Agent JSON output with proper error handling
  const rawOutput = $input.first().json.output;

  // Clean the escaped characters step by step
  let cleanedOutput = rawOutput
    .replace(/\\n/g, '\n')      // Convert literal \n to actual newlines
    .replace(/\\"/g, '"')       // Convert escaped quotes to regular quotes
    .replace(/\\\\/g, '\\');    // Handle double-escaped backslashes

  // Parse the JSON with error handling
  let parsedOutput;
  try {
    parsedOutput = JSON.parse(cleanedOutput);
  } catch (error) {
    // If that fails, try replacing newlines with spaces instead
    cleanedOutput = rawOutput
      .replace(/\\n/g, ' ')     // Replace newlines with spaces
      .replace(/\\"/g, '"')     // Convert escaped quotes
      .replace(/\\\\/g, '\\');  // Handle escaped backslashes

    try {
      parsedOutput = JSON.parse(cleanedOutput);
    } catch (secondError) {
      // If still failing, return error info for debugging
      return {
        error: 'JSON parsing failed',
        rawOutput: rawOutput,
        cleanedOutput: cleanedOutput,
        parseError: secondError.message
      };
    }
  }

  // Return clean, parsed fields
  return {
    spiritualFocus: parsedOutput.spiritualFocus || 'No spiritual focus available',
    liturgicalReadings: parsedOutput.liturgicalReadings || parsedOutput.liturgicalInsight || 'No
   liturgical insight available',
    saintOfTheDay: parsedOutput.saintOfTheDay || null,
    reflection: parsedOutput.reflection || 'No reflection available',
    practicalChallenge: parsedOutput.practicalChallenge || 'No practical challenge available',
    prayer: parsedOutput.prayer || 'No prayer available'
  };
